--
-- Table structure for table `sales`
--

DROP TABLE IF EXISTS `sales`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sales` (
  `sale_id` int(11) NOT NULL AUTO_INCREMENT,
  `sale_datetime` datetime DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `client_id` int(11) DEFAULT NULL,
  `total` decimal(10,2) NOT NULL DEFAULT 0.00,
  `payment_method` varchar(50) DEFAULT NULL,
  `iva` decimal(10,2) DEFAULT 0.00,
  `is_return` tinyint(1) DEFAULT 0,
  `return_reason` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `returned_amount` decimal(10,2) DEFAULT 0.00,
  `closure_id` int(11) DEFAULT NULL,
  `doc_type` varchar(20) DEFAULT NULL,
  `doc_series` varchar(10) DEFAULT NULL,
  `doc_number` int(11) DEFAULT NULL,
  `doc_status` varchar(20) DEFAULT NULL,
  `origin_sale_id` int(11) DEFAULT NULL,
  `control_hash` varchar(64) DEFAULT NULL,
  `total_net` decimal(10,2) DEFAULT 0.00,
  `total_tax` decimal(10,2) DEFAULT 0.00,
  `customer_name_snapshot` varchar(255) DEFAULT NULL,
  `discount_amount` decimal(10,2) DEFAULT 0.00,
  `discount_reason` varchar(255) DEFAULT NULL,
  `cash_amount` double DEFAULT 0,
  `card_amount` double DEFAULT 0,
  `observations` text DEFAULT NULL,
  PRIMARY KEY (`sale_id`),
  KEY `idx_sales_user_date` (`user_id`,`sale_datetime`),
  KEY `idx_sales_client_date` (`client_id`,`sale_datetime`),
  KEY `idx_sales_datetime` (`sale_datetime`),
  KEY `idx_sales_payment` (`payment_method`),
  KEY `idx_sales_closure` (`closure_id`),
  KEY `idx_sales_is_return` (`is_return`),
  KEY `idx_sales_doc_series` (`doc_series`),
  KEY `idx_sales_doc_number` (`doc_series`,`doc_number`),
  KEY `idx_sales_doc_status` (`doc_status`),
  KEY `idx_sales_doc_type` (`doc_type`),
  KEY `idx_sales_amount` (`total`),
  CONSTRAINT `fk_sales_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL,
  CONSTRAINT `sales_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`),
  CONSTRAINT `sales_ibfk_2` FOREIGN KEY (`client_id`) REFERENCES `clients` (`client_id`)
) ENGINE=InnoDB AUTO_INCREMENT=395 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
